<template>
  <v-container fluid align-start ma-0 pa-0 class="qa-container">
    <v-row no-gutters v-if="files.length > 0">
      <v-col md="12" lg="9">
        <span class="editor-label">{{ $t('attachment') }}</span>
        <div class="edit-layout">
          <v-card
            v-for="file in files"
            :key="file.id"
            :color="saveFileList.delete.includes(file) ? '#DEE2E8' : '#EEF1F5'"
            flat
            width="200"
            class="edit-spacing"
          >
            <div class="edit-card">
              <v-tooltip top>
                <template v-slot:activator="{ on, attrs }">
                  <p
                    v-bind="attrs"
                    v-on="on"
                    :class="{ strikethrough: saveFileList.delete.includes(file) }"
                    class="file-text"
                    @click="fileDownload(file)"
                  >
                    {{ file.fileNm }}.{{ file.extension }}
                  </p>
                </template>
                <span>{{ file.fileNm }}.{{ file.extension }}</span>
              </v-tooltip>

              <v-btn icon class="download-color" @click="fileDownload(file)"><svg-icon icon-class="download" width="20"/></v-btn>
              <v-btn v-if="!readOnly" icon class="error-color">
                <svg-icon :icon-class="saveFileList.delete.includes(file) ? 'reload' : 'delete'" @click="toggleFileRemove(file)" />
              </v-btn>
            </div>
            <div class="file-size">{{ file.fileSize }}</div>
          </v-card>
        </div>
      </v-col>
    </v-row>

    <v-sheet no-gutters v-if="!readOnly" style="width:100%;" :class="{ 'mt-5': files.length > 0 }">
      <span class="editor-label pa-0">{{ $t('uploadFile') }}</span>
      <v-layout column>
        <div style="text-align: right;" class="widget-container">
          <DxFileUploader
            :ref="dxFileUploader"
            :accept="fileExtension"
            :multiple="true"
            upload-mode="useButtons"
            :show-file-list="false"
            select-button-text="업로드"
            labelText
            width="100%"
            :dialog-trigger="'#btnUpload' + id"
            drop-zone="#dropzone-external"
            @uploaded="onUploaded"
            @upload-error="onUploadError"
            @value-changed="onValueChanged"
            :visible="false"
          />
        </div>

        <!-- 드래그 존  -->
        <div id="dropzone-external" :class="{ newFile: newFiles.length > 0 }">
          <div class="file-icon">
            <svg-icon icon-class="file-success" width="20" />
          </div>
          <span class="file-notice01">{{ $t('dropFileHere') }}</span>
          <section class="newFile-top">
            <v-card v-for="file in newFiles" :key="file.id" flat width="200" class="upload-spacing" color="#EEF1F5">
              <div class="upload-card">
                <p class="file-text new">{{ file.fileNm }}.{{ file.extension }}</p>
                <v-btn icon class="error-color" @click="newFileRemove(file)"><svg-icon icon-class="delete" width="24"/></v-btn>
              </div>
              <div class="file-size">{{ file.fileSize }}</div>
            </v-card>
          </section>
          <section class="newFile-bottom">
            <span class="file-notice02">{{ $t('OnlyFilesUnder100MB') }}</span>
            <v-btn :id="'btnUpload' + id" text>{{ $t('uploadFiles') }}</v-btn>
          </section>
        </div>
      </v-layout>
    </v-sheet>
  </v-container>
</template>

<script>
import { deleteFile, downloadFile, getFile, multiFileUpload } from '@/api/baseManage/fileUpload'
import baseview from '@/views/base/baseview.vue'
import BaseDataGrid from '@/views/base/BaseDataGrid.vue'
import { getCurrentDate } from '@/utils/common.js'
import notify from 'devextreme/ui/notify'

import { DxFileUploader } from 'devextreme-vue/file-uploader'

export default {
  mixins: [baseview, BaseDataGrid],
  name: 'iFileManage',
  components: { DxFileUploader },
  props: {
    id: {
      // dialog-trigger 중복 방지를 위한 ID 값
      type: String,
      default: () => ''
    },
    targetId: {
      type: String,
      default: () => ''
    },
    targetType: {
      type: String,
      default: () => ''
    },
    readOnly: {
      type: Boolean,
      default: false
    },
    fileExtension: {
      type: String,
      default: () => '*'
    }
  },
  data() {
    return {
      componentKey: 0,
      buttonUseList: [
        'btnUpload' //업로드
      ],
      dxDataGridRef: 'fileDataGrid',
      dxFileUploader: 'uploaderContainer',
      files: [],
      newFiles: [],
      maxFileSize: 104857600,
      saveFileList: {
        insert: [],
        delete: []
      }
    }
  },
  watch: {
    targetId() {
      // 신규 문서일시 초기화
      if (this.targetId === '') {
        this.files = []
        this.newFiles = []
      }
    }
  },
  computed: {
    fileUploader: function() {
      return this.$refs[this.dxFileUploader].instance
    }
  },
  beforeMount() {},
  created() {},
  mounted() {},
  activated() {
    // 신규 문서일시 초기화
    if (this.targetId === '') {
      this.files = []
      this.newFiles = []
    }
  },
  methods: {
    forceRerender() {
      this.componentKey += 1
    },

    btnSearch(noti, targetId = this.targetId, compId = this.getCompId()) {
      this.openLoading()
      let searchParams = {
        targetId: targetId,
        targetType: this.targetType,
        compId: compId
      }

      getFile(searchParams, noti)
        .then(res => {
          if (res.success) {
            this.files = res.list.filter(el => el.targetId === searchParams.targetId)
          }
        })
        .finally(() => this.endLoading())
    },

    async btnSave(fileList) {
      await this.fileRemove(fileList.delete) // 삭제리스트 파일 삭제
      await this.fileSave(fileList.insert)
      this.saveFileList = {
        insert: [],
        delete: []
      }
      this.newFiles = []
    },

    fileSave(selectedRows) {
      if (selectedRows.length > 0) {
        return new Promise((resolve, reject) => {
          this.openLoading()
          let formData = new FormData()
          let i = 0
          selectedRows.forEach(element => {
            formData.append('fileList[' + i + '].fileData', element.file ? element.file : new Blob([], { type: 'application/octet-stream' }))
            formData.append('fileList[' + i + '].fileVO.targetId', this.targetId)
            formData.append('fileList[' + i + '].fileVO.targetType', this.targetType)
            formData.append('fileList[' + i + '].fileVO.useYn', element.useYn)
            i++
          })
          multiFileUpload(formData, false)
            .then(res => {
              if (res.success) {
                this.btnSearch(false)
              }
            })
            .finally(() => {
              this.endLoading()
              resolve(true)
            })
        })
      }
    },
    fileRemove(files) {
      if (files.length > 0) {
        this.openLoading('deleting')
        deleteFile(files, false)
          .then(res => {
            if (res.success) {
              this.btnSearch(false)
            }
          })
          .finally(() => {
            this.endLoading()
          })
      }
    },

    newFileRemove(file) {
      const currentIndex = this.saveFileList.insert.indexOf(file)
      this.saveFileList.insert.splice(currentIndex, 1)
      this.newFiles = this.newFiles.filter(row => row.id !== file.id)
    },

    fileDownload(rowData) {
      this.openLoading()
      // api 에 responseType: "blob" 필수, 백단에 byteArray(Blob)형태로 보내고 있기 때문
      downloadFile(rowData.fileId)
        .then(res => {
          let link = document.createElement('a')
          // 객체를 만들어서 생성
          let objectUrl = window.URL.createObjectURL(res)
          link.href = objectUrl
          link.download = `${rowData.fileNm}.${rowData.extension}`
          link.click()
        })
        .finally(() => this.endLoading())
    },

    onUploaded(e) {
      e.component._files.forEach((element, index) => {
        if (element._isLoaded) {
          this.fileUploader.removeFile(index)
        }
      })
      notify(this.$t('파일이 업로드 되었습니다.'), 'success', 300)
    },

    onUploadError(e) {
      e.component._files.forEach((element, index) => {
        if (element._isError) {
          this.fileUploader.removeFile(index)
          this.vSnackbar(this.$t('파일을 업로드 할 수 없습니다.'), 'info')
        }
      })
    },

    onValueChanged(e) {
      // reset 이벤트는 재귀적으로 이 이벤트를 부르기 때문에 0일때 return 시킴
      if (e.value == null || e.value.length == 0) return

      this.openLoading()
      for (const element of e.value) {
        if (element.size >= this.maxFileSize) {
          this.vSnackbar(this.$t('파일이 용량이 100MB를 초과했습니다.'), 'info')
          continue
        }
        let subFileName = this.getExtension(element.name)
        let writeDt = getCurrentDate()
          .split('-')
          .join('')
        let newRow = {
          id: this.newFiles.length + 1,
          writeDt: writeDt,
          doc_no: (this.files.length + 1).toString().padStart(5, '0'),
          file: new File([element], `${subFileName[0]}.${subFileName[1]}`),
          fileNm: subFileName[0],
          extension: subFileName[1],
          fileSize: this.getfileSize(element.size),
          useYn: 'Y',
          targetId: this.targetId,
          targetType: this.targetType,
          compId: this.getCompId()
        }

        this.newFiles.unshift(newRow)
        this.saveFileList.insert = [...this.saveFileList.insert, ...[newRow]]
      }
      this.fileUploader.reset()
      this.$emit('onFileChanged', this.saveFileList)
      this.endLoading()
    },

    getExtension(fileName) {
      let fileLen = fileName.length

      let lastDot = fileName.lastIndexOf('.')
      let extension = fileName.substring(lastDot + 1, fileLen).toLowerCase()
      let baseName = fileName.substring(0, lastDot)
      return [baseName, extension]
    },

    getfileSize(size) {
      let fileSize = ''
      if (size < 1048576) {
        fileSize = (size / 1024).toFixed(3) + 'KB'
      } else {
        fileSize = (size / 1048576).toFixed(3) + 'MB'
      }
      return fileSize
    },

    openFileDialog() {
      // DxFileUploader의 내부 input에 접근하여 클릭 이벤트를 트리거
      this.$refs.dxFileUploader.$el.querySelector('.dx-fileuploader-input').click()
    },

    toggleFileRemove(file) {
      const currentIndex = this.saveFileList.delete.indexOf(file)
      if (currentIndex === -1) {
        this.saveFileList.delete.push(file)
      } else {
        this.saveFileList.delete.splice(currentIndex, 1)
      }
      this.$emit('onFileChanged', this.saveFileList)
    }
  }
}
</script>

<style lang="scss">
.qa-container {
  padding: 0%;
}

#dropzone-external {
  min-height: 160px;
  padding: 24px;
  background-color: #fbfcfe;
  border: 1px solid #e4e4ed;
  border-radius: 4px;
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  .file-icon {
    width: 48px;
    height: 48px;
    display: flex;
    justify-content: center;
    align-items: center;
    border-radius: 100%;
    background: #eef0f4;
    color: #130953 !important;
  }
  .file-notice01 {
    color: rgba(0, 0, 0, 0.25);
    font-size: 15px;
    font-weight: 600;
    margin: 12px auto 8px;
  }
  .file-notice02 {
    font-size: 12px;
    color: rgba(0, 0, 0, 0.25);
    font-weight: 400;
  }
  .newFile-top {
    width: 100%;
    display: flex;
    flex-wrap: nowrap;
    overflow-x: auto;
    padding-bottom: 8px;
  }
  .newFile-bottom {
    display: flex;
    flex-direction: column;
    align-items: center;
  }
  #btnUpload {
    padding: 0;
    height: unset;
    margin-top: 8px;
    .v-btn__content {
      font-size: 15px;
      font-weight: 500;
      border-bottom: 1px solid #130953;
      color: #000;
    }
  }
  &.newFile {
    align-items: flex-start;
    .file-icon,
    .file-notice01 {
      display: none;
    }
    .newFile-bottom {
      width: 100%;
      flex-direction: row;
      justify-content: space-between;
      align-items: flex-end;
    }
  }
}

.file-text {
  color: #000;
  font-size: 12px;
  width: 100%;
  margin-bottom: 0 !important;
  white-space: nowrap; /* 텍스트가 요소의 영역을 벗어나지 않도록 함 */
  overflow: hidden; /* 요소 내부의 내용이 영역을 벗어나면 숨김 */
  text-overflow: ellipsis; /* 텍스트가 잘리면 ...으로 표시 */
  &:not(.new) {
    text-decoration: underline; /* 텍스트에 밑줄 추가 */
  }
}

// 다운로드용
.file-text:hover {
  cursor: pointer; /* 마우스가 요소 위에 있을 때 커서를 포인터 모양으로 변경 */
}

.file-size {
  color: rgba(0, 0, 0, 0.5);
  font-size: 12px;
  margin-top: 16px;
}

// 파일 취소선 (삭제선)
.strikethrough {
  text-decoration: line-through !important;
  color: #a0a6b5;
}

// 업로드 카드관련
.upload-card {
  display: flex;
  align-items: center;
}

.upload-spacing {
  margin-right: 8px;
  padding: 12px;
}

// 첨부파일 카드관련
.edit-card {
  display: flex;
  align-items: center;
}

.edit-spacing {
  margin-right: 8px;
  padding: 12px;
}

.edit-layout {
  display: flex;
  flex-wrap: wrap;
}

.error-color {
  color: red !important;
}

.download-color {
  color: #2F4F8F !important;
}
</style>
