<template>
  <v-container class="main-container">
    <v-sheet>
      <div class="top-row">
        <span v-if="!addYn">
          <span style="margin-right: 25px;">
            {{ $t('writer') + ' :' }}
            <span span class="font-weight-bold"> {{ '\u00A0' + (editingData.reporterNm || '') }}</span>
          </span>
          <span style="margin-right: 25px;">
            {{ $t('QACreatedDate') + ' :' }}
            <span span class="font-weight-bold">{{ '\u00A0' + (editingData.createdAt || '') }}</span>
          </span>
          <span style="margin-right: 25px;">
            {{ $t('QAStatus') + ' :' }}
            <span span class="font-weight-bold">{{ '\u00A0' + (customerInquiryStatusDesc || '') }}</span>
          </span>
          <span>
            {{ $t('processingDate') + ' :' }}
            <span span class="font-weight-bold">{{ '\u00A0' + (editingData.solvedAt || '') }}</span>
          </span>
        </span>
        <span></span>
        <span>
          <!-- btn_sub 안됨 -->
          <span v-if="addYn || isSuperGrp || isMyContent">
            <v-btn color="#56a4ff" elevation="0" dark small style="margin-right: 4px; border-radius: 4px;" @click="btnSave">
              {{ $t('btnSave') }}
            </v-btn>
          </span>
          <span v-if="!addYn && isMyContent">
            <v-btn color="#56a4ff" elevation="0" dark small style="margin-right: 4px; border-radius: 4px;" @click="btnDelete">
              {{ $t('btnDelete') }}
            </v-btn>
          </span>
          <span v-if="isMyContent && (customerInquiryStatus === 'STATUS_04' || customerInquiryStatus === 'STATUS_05')">
            <v-btn color="#56a4ff" elevation="0" dark small style="margin-right: 4px; border-radius: 4px;" @click="btnReconfirmation">
              {{ $t('btnReconfirmation') }}
            </v-btn>
          </span>
        </span>
      </div>
      <hr class="custom-hr" />
      <v-row no-gutters>
        <v-col cols="9" style="padding-right: 10px; padding-bottom: 10px;">
          <span>{{ $t('QATitle') + '*' }}</span>
          <v-text-field
            v-model="editingData.subject"
            class="search-text-field mx-1"
            outlined
            dense
            hide-details="auto"
            clearable
            :disabled="!isMyContent"
          />
        </v-col>
        <v-col cols="3" style="padding-right: 10px;">
          <span>{{ $t('modificationRequestDate') }}</span>
          <i-date-time-picker
            :firstDisplayDate="firstDisplayDate"
            :allowMinDate="startDate"
            :dateOnly="true"
            :placeholder="$t('modificationRequestDate')"
            class="mx-1"
            @getDate="setrequestDate($event, 'start')"
            :disabled="!isMyContent"
          >
          </i-date-time-picker>
        </v-col>
      </v-row>
      <v-row no-gutters>
        <v-col cols="12" style="padding-right: 10px; padding-bottom: 10px;">
          <span>
            {{ $t('contents') }}
            <v-tooltip top>
              <template v-slot:activator="{ on, attrs }">
                <v-icon small v-bind="attrs" v-on="on" style="padding-bottom: 3px;">
                  mdi-help-circle
                </v-icon>
              </template>
              <span>
                {{ $t('msgWriteProblems') }}
              </span>
            </v-tooltip>
          </span>
          <v-textarea v-model="editingData.content" outlined clearable no-resize auto-grow :disabled="!isMyContent"></v-textarea>
        </v-col>
      </v-row>
      <v-row no-gutters>
        <v-col cols="12" style="padding-right: 10px; padding-bottom: 10px;">
          <span>
            {{ $t('modiAddRequests') }}
            <v-tooltip top>
              <template v-slot:activator="{ on, attrs }">
                <v-icon small v-bind="attrs" v-on="on" style="padding-bottom: 3px;">
                  mdi-help-circle
                </v-icon>
              </template>
              <span>
                {{ $t('msgWriteRequests') }}
              </span>
            </v-tooltip>
          </span>
          <v-textarea v-model="editingData.contentReq" outlined clearable no-resize auto-grow :disabled="!isMyContent"></v-textarea>
        </v-col>
      </v-row>
      <v-row no-gutters>
        <!-- 파일 -->
        <v-col cols="12" style="padding-right: 10px; padding-bottom: 10px;">
          <iFileManage ref="detailFileUpload" :targetId="targetId" targetType="QA" @onFileChanged="onFileChanged" />
        </v-col>
      </v-row>
      <v-row no-gutters>
        <v-col v-if="!addYn" cols="3" style="padding-right: 10px; padding-bottom: 10px;">
          <span>{{ $t('QAStatus') }}</span>
          <v-select
            :placeholder="$t('QAStatus')"
            class="mx-1"
            :menu-props="{ offsetY: true }"
            item-text="minorNm"
            item-value="minorCd"
            :items="statusList"
            dense
            outlined
            v-model="editingData.status"
            :readonly="!isSuperGrp"
            attach="#attach1"
          >
            <template v-slot:prepend>
              <div :id="`attach1`"></div>
            </template>
          </v-select>
        </v-col>
      </v-row>
      <v-row no-gutters>
        <v-col v-if="!addYn" cols="12" style="padding-right: 10px;">
          <span>{{ $t('answer') }}</span>
          <v-textarea v-model="editingData.replyContent" outlined clearable auto-grow no-resize :disabled="!isSuperGrp"></v-textarea>
        </v-col>
      </v-row>
    </v-sheet>
  </v-container>
</template>

<script>
import baseview from '@/views/base/baseview.vue' //20220414 LYJ base page 추가
import { getCurrentDate } from '@/utils/common.js'
import { getUserCd, getGrpAuthCd } from '@/utils/token'
import { getCommonCode } from '@/api/common/commonApi'
import iDateTimePicker from '@/components/common/iDateTimePicker.vue'
import notify from 'devextreme/ui/notify'
import iFileManage from '@/components/common/iFileManage.vue'

import { saveBugReport, deleteBugReport } from '@/api/support/bugReport'

export default {
  mixins: [baseview], //20220414 LYJ base page 추가 및 권한 처리
  components: {
    'i-date-time-picker': iDateTimePicker,
    iFileManage
  },
  props: {
    //고객문의 조회데이터
    cellInfo: {
      type: Object
    },
    //추가(new)인지 여부
    addYn: {
      type: Boolean,
      required: true
    }
  },
  data() {
    return {
      dxFileUploader: 'uploaderContainer',
      editingData: [], //고객지원 상세 팝업 데이터
      statusList: [], //C0039 고객문의 처리상태 리스트
      customerInquiryStatusDesc: null, //상단 처리상태
      customerInquiryStatus: null, //
      startDate: getCurrentDate(0), //수정요청일 : 오늘 이후로만 선택가능
      firstDisplayDate: null, //수정요청일 초기값

      fileList: {
        insert: [],
        delete: []
      },
      targetId: ''
    }
  },
  watch: {
    //고객문의 화면에서 데이터 들고옴
    cellInfo(val) {
      this.initializeData()
    }
  },
  computed: {
    fileUploader: function() {
      return this.$refs[this.dxFileUploader].instance
    },
    isMyContent() {
      // 로그인한 계정의 게시글만 수정 가능
      if (this.addYn) return true
      return getUserCd() === this.editingData.createdBy
    },
    isSuperGrp() {
      // 마스터 그룹만 답변 수정 가능
      return getGrpAuthCd() === 'super'
    },
    getType() {
      // 타입 설정 : 문의/사용자(Q), 문의수정(E), 답변/관리자(A), 재확인요청/사용자,관리자(R) -> 재확인요청은 따로관리
      if (this.isSuperGrp) {
        return 'A'
      } else if (this.isMyContent && this.addYn) {
        return 'Q'
      } else {
        return 'E'
      }
    }
  },
  mounted() {
    //데이터 초기화 및 공통코드 리스트 조회
    this.setComboBoxData()
  },
  methods: {
    setComboBoxData() {
      Promise.all([getCommonCode('C0039') /* 처리상태*/]).then(response => {
        this.statusList = response[0].list.slice()
        this.dsStatus = response[0].list.slice()
        //상단 처리상태 명으로 표시하는 것때문에 initializeData 여기서 처리
        //TODO: 처음 로딩이 길거나하면 수정해야될듯
        this.initializeData()
      })
    },
    initializeData() {
      if (this.addYn) {
        this.editingData = {
          compId: this.getCompId(),
          subject: null,
          requestedDate: null,
          content: null,
          contentReq: null,
          status: 'STATUS_00', //초기값은 '미처리'
          replyContent: null
        }
        this.targetId = ''
      } else {
        // 'yyyy.mm.dd' 형식으로 변환합니다.
        const createdAtDate = new Date(this.cellInfo.data.createdAt)
        const formattedDate1 = createdAtDate
          .toISOString()
          .split('T')[0]
          .replace(/-/g, '.')

        const solvedAtDate = new Date(this.cellInfo.data.solvedAt)
        const formattedDate2 =
          this.cellInfo.data.solvedAt != null
            ? solvedAtDate
                .toISOString()
                .split('T')[0]
                .replace(/-/g, '.')
            : null

        this.editingData = { ...this.cellInfo.data, createdAt: formattedDate1, solvedAt: formattedDate2 }

        this.targetId = this.editingData.seq.toString()
        this.$refs.detailFileUpload.btnSearch(false, this.targetId, this.editingData.compId)
      }

      //수정요청일 초기값 세팅
      this.firstDisplayDate = this.editingData.requestedDate

      //상단 처리상태 명으로 표시하기 위함
      if (this.statusList.length != 0) {
        this.customerInquiryStatus = this.editingData.status
        this.customerInquiryStatusDesc = this.statusList.find(item => item.minorCd === this.editingData.status).minorNm
      }
    },
    ///////////////////////////////////////
    /*       Toolbar Button Event        */
    ///////////////////////////////////////
    async btnSave() {
      if (
        this.editingData.subject == null ||
        this.editingData.subject == '' ||
        this.editingData.content == null ||
        this.editingData.content == '' ||
        this.editingData.contentReq == null ||
        this.editingData.contentReq == ''
      ) {
        this.vToastify('필수항목 입력하세요.[제목, 내용, 수정/추가 요청사항]', 'warn')
        return
      }

      var selectedRows = {
        seq: this.editingData.seq,
        compId: this.getCompId(),
        subject: this.editingData.subject,
        requestedDate: this.editingData.requestedDate,
        content: this.editingData.content,
        contentReq: this.editingData.contentReq,
        status: this.editingData.status,
        replyContent: this.editingData.replyContent,
        type: this.getType //사용자, 관리자, 상황에 따라 다른 type -> computed()에서 가져옴
      }

      this.vToastifyPrompt(this.$t('doSaveData'), 'info', current => {
        this.openLoading()
        saveBugReport(selectedRows, false)
          .then(res => {
            if(res.seq){
              this.targetId = res.seq;
            }
            notify(this.$t('saved'), 'success', 800)
            this.$emit('popupClose')
            // 저장 성공시 첨부 파일처리 - 신규 문서 targetId 할당 받기 위해 finally로 위치 변경
            if (this.fileList.insert.length !== 0 || this.fileList.delete.length !== 0) {
              this.$refs.detailFileUpload.btnSave(this.fileList)
              this.fileList = {
                insert: [],
                delete: []
              }
            }
            this.endLoading()
          })
          .catch(e => {})
          .finally(() => {
          })
      })
    },

    async btnDelete() {
      var selectedRows = {
        seq: this.editingData.seq
      }

      this.vToastifyPrompt(this.$t('doDeleteData'), 'info', current => {
        this.openLoading()
          deleteBugReport(selectedRows)
          .then(res => {
            if (res.success) {
              this.$refs.detailFileUpload.fileRemove(this.$refs.detailFileUpload.files)
              notify(this.$t('deleted'), 'success', 800)
              this.$emit('popupClose')
              this.endLoading()
            }
          })
          .catch(e => {})
          .finally(() => {})
      })
    },
    async btnReconfirmation() {
      var selectedRows = {
        seq: this.editingData.seq,
        type: 'R'
      }

      this.vToastifyPrompt(this.$t('재확인 요청하시겠습니까?'), 'info', current => {
        this.openLoading()
        saveBugReport(selectedRows, false)
          .then(res => {
            if (res.success) {
              notify(this.$t('관리자에게 재확인요청하였습니다.'), 'success', 800)
              this.$emit('popupClose')
            }
          })
          .catch(e => {})
          .finally(() => {
            this.endLoading()
          })
      })
    },

    //수정요청일 변경값 세팅
    setrequestDate(e, div) {
      this.editingData.requestedDate = e.replace(/[^0-9]/g, '')
    },
    onFileChanged(fileList) {
      this.fileList = fileList
    },
    //파일
    onUploaded(e) {
      e.component._files.forEach((element, index) => {
        if (element._isLoaded) {
          this.fileUploader.removeFile(index)
        }
      })
      notify(this.$t('파일이 업로드 되었습니다.'), 'success', 300)
    },
    onUploadError(e) {
      e.component._files.forEach((element, index) => {
        if (element._isError) {
          this.fileUploader.removeFile(index)
          notify(this.$t('파일을 업로드 할 수 없습니다.'), 'error', 300)
        }
      })
    }
  }
}
</script>
<style scoped>
/* 작성자, 작성일, 처리완료, 처리일자 */
.top-row {
  display: flex !important ;
  justify-content: space-between;
}
</style>
<style lang="scss">
.main-container {
  padding: 28px;
  padding-bottom: 150px;
}
.custom-hr {
  border: 0;
  height: 1px;
  background-color: #d3d3d3;
  margin: 10px 0;
}

//TODO: 왜 이것만 폰트가 적용안되는지 이유를 못찾음
.v-text-field input {
  font-family: Pretendard, -apple-system, BlinkMacSystemFont, system-ui, Roboto, 'Helvetica Neue', 'Segoe UI', 'Apple SD Gothic Neo', 'Noto Sans KR',
    'Malgun Gothic', sans-serif !important;
  font-weight: 500;
  letter-spacing: 0.05em !important;
}
</style>
