<template>
  <v-container fluid fill-height align-start ma-0 pa-2 class="bug-report">
    <v-row no-gutters>
      <v-col cols="12" sm="12" md="12" class="pa-2 pb-0">
        <i-dxpopup
          :popupVisible="popupVisible"
          :title="$t(popupTitle)"
          @popupCloseButtonClick="popupClose"
          :vHtmlContent="'test'"
          :height="'800'"
          width="50vw"
        >
          <template v-slot:grid>
            <HelpPopup :cellInfo="selectedCellInfo" :addYn="addYn" @popupClose="popupClose"></HelpPopup>
          </template>
        </i-dxpopup>
        <i-card-top class="d-md-flex" :headerTitle="$t('customerQA')" :useBtnList="buttonUseList" @btnSearch="btnSearch()" @btnAdd="btnAdd()">
          <template v-slot:body>
            <v-layout>
              <v-row no-gutters class="pa-0 pt-2">
                <v-col cols="12" md="4">
                  <v-row no-gutters>
                    <v-col>
                      <i-date-time-picker
                        :firstDisplayDate="startDate"
                        :placeholder="$t('reportDate')"
                        class="mx-1"
                        :dateOnly="true"
                        @getDate="setSearchDate($event, 'start')"
                      >
                      </i-date-time-picker>
                    </v-col>
                    <span class="pt-1">
                      ~
                    </span>
                    <v-col>
                      <i-date-time-picker
                        :firstDisplayDate="endDate"
                        :placeholder="$t('reportDate')"
                        class="mx-1"
                        :dateOnly="true"
                        @getDate="setSearchDate($event, 'end')"
                      >
                      </i-date-time-picker>
                    </v-col>
                  </v-row>
                </v-col>
              </v-row>
            </v-layout>
          </template>
        </i-card-top>
      </v-col>
      <v-col cols="12" sm="12" md="12" class="pa-2 pt-0">
        <i-card-vertical :headerTitle="$t('customerQA')" device="web">
          <template v-slot:body>
            <v-col cols="12" md="12" class="row pa-0">
              <v-col cols="12" lg="12" class="pa-0 ">
                <DxDataGrid
                  id="dxDataGrid"
                  class="layout-col-height00"
                  width="100%"
                  :ref="dxDataGridRef"
                  :data-source="gridMain"
                  :show-row-lines="true"
                  :selection="{ mode: 'single' }"
                  key-expr="seq"
                  @editing-start="onEditingStart"
                  @editor-preparing="onEditorPreparing"
                  :remote-operations="false"
                  :hover-state-enabled="true"
                  :allow-column-resizing="true"
                  :allow-column-reordering="true"
                  :row-alternation-enabled="true"
                  :column-auto-width="false"
                  :column-hiding-enabled="false"
                  :show-borders="true"
                  :focused-row-enabled="true"
                >
                  <DxEditing mode="batch" :allow-updating="true" :select-text-on-edit-start="true" />

                  <DxSelection :select-all-mode="allMode" mode="single" />

                  <DxColumn data-field="seq" :visible="false"> </DxColumn>
                  <DxColumn data-field="compId" :caption="$t('QACompCode')" data-type="string" alignment="center" width="150"> </DxColumn>
                  <DxColumn data-field="subject" :caption="$t('QATitle')" data-type="string" alignment="left" width="350"> </DxColumn>
                  <DxColumn data-field="content" :caption="$t('contents')" data-type="string" alignment="left" width="480"> </DxColumn>
                  <DxColumn
                    data-field="save"
                    data-type="string"
                    width="120"
                    alignment="center"
                    caption=""
                    :allow-editing="false"
                    cell-template="actionTemplete"
                  >
                  </DxColumn>
                  <template #actionTemplete="{ data: cellInfo }">
                    <div>
                      <v-btn color="btn_sub" elevation="0" dark small @click="showPopup(cellInfo)" class="mr-2 rounded">
                        {{ $t('showDetail') }}
                      </v-btn>
                    </div>
                  </template>
                  <DxColumn
                    data-field="reporterNm"
                    :caption="$t('QAreporter')"
                    width="120"
                    data-type="string"
                    alignment="center"
                    :allow-editing="false"
                  >
                  </DxColumn>
                  <DxColumn
                    data-field="createdAt"
                    :caption="$t('reportDate')"
                    width="120"
                    data-type="date"
                    format="yyyy.MM.dd"
                    alignment="center"
                    :allow-editing="false"
                  >
                  </DxColumn>
                  <DxColumn data-field="status" :caption="$t('QAStatus')" width="120" data-type="string" alignment="center" :allow-editing="true">
                    <DxLookup :data-source="dsStatus" value-expr="minorCd" display-expr="minorNm" value="minorCd" />
                  </DxColumn>
                  <DxColumn
                    data-field="solvedAt"
                    :caption="$t('processingDate')"
                    width="120"
                    data-type="date"
                    format="yyyy.MM.dd"
                    alignment="center"
                    :allow-editing="false"
                  >
                  </DxColumn>
                </DxDataGrid>
              </v-col>
            </v-col>
          </template>
        </i-card-vertical>
      </v-col>
    </v-row>
  </v-container>
</template>

<script>
import { DxDataGrid, DxColumn, DxSelection, DxLookup, DxEditing, DxFilterRow } from 'devextreme-vue/data-grid'
import iCardTop from '@/components/common/iCardTop.vue'
import iCardVertical from '@/components/common/iCardVertical.vue'
import IDateTimePicker from '@/components/common/iDateTimePicker.vue'
import { getCurrentDate, getPreMonth, getDateEditorValue } from '@/utils/common.js'
import { getBugReport } from '@/api/support/bugReport'
import { getUserList } from '@/api/system/userManage' //사용자정보
import HelpPopup from '@/views/support/HelpPopup.vue'
import iDxPopup from '@/components/common/iDxPopup.vue'
import baseview from '@/views/base/baseview.vue' //20220414 LYJ base page 추가
import BaseDataGrid from '@/views/base/BaseDataGrid.vue' //20220509 LYJ 데이타 그리드 사용시 베이스 추가
import { getCommonCode } from '@/api/common/commonApi'

export default {
  mixins: [baseview, BaseDataGrid], //20220414 LYJ base page 추가 및 권한 처리
  components: {
    'i-dxpopup': iDxPopup,
    HelpPopup,
    DxDataGrid,
    DxColumn,
    DxSelection,
    DxEditing,
    DxLookup,
    'i-card-vertical': iCardVertical,
    'i-card-top': iCardTop,
    'i-date-time-picker': IDateTimePicker
  },
  data() {
    return {
      popupVisible: false,
      allMode: 'allPages',
      txtSubjectName: '',
      dxDataGridRef: 'dxDataGrid',
      gridMain: [],
      buttonUseList: [
        'btnSearch', //조회
        'btnAdd' // 추가
      ],
      popupTitle: '',
      dxFileUploaderRef: 'uploaderContainer',
      fileData: {},
      files: [],
      currentCellInfo: null,
      bugReportStatusList: [],
      dsStatus: [],
      dsSupportList: [],
      dsSupportMan: [],
      dsSupportBusiness: [],
      bugReportStatus: '',

      bolCustomerSupply: true,
      startDate: getPreMonth(+1),
      endDate: getCurrentDate(0),
      searchStartDate: getPreMonth(+1),
      searchEndDate: getCurrentDate(0).replace(/[^0-9]/g, ''),
      //팝업 props
      selectedCellInfo: null,
      addYn: true
    }
  },
  beforeMount() {
    this.BaseInitialize()
    this.datagridRefs = [this.dxDataGridRef]

    Promise.all([getCommonCode('C0039') /* 문제보고상태*/, getUserList()] /* 고객지원 유저 */).then(response => {
      // 문제보고상태[조회조건][0]
      this.bugReportStatusList = response[0].list.slice()
      this.dsStatus = response[0].list.slice()
      this.bugReportStatusList.unshift({ minorCd: '', minorNm: '전체' })
      //고객지원 유저[1]
      this.dsSupportList = response[1].list.slice()
    })
  },

  mounted() {},

  computed: {
    getFileData() {
      return this.fileData
    }
  },
  activated() {
    if (this.$route.params) {
      this.btnSearch(true).then(res => {
        if (this.$route.params.focusedRowKey) this.DataGrids[0].option('focusedRowKey', this.$route.params.focusedRowKey)
      })
    }
    Promise.all([getCommonCode('C0039') /* 문제보고상태*/, getUserList()] /* 고객지원 유저 */).then(response => {
      // 문제보고상태[조회조건][0]
      this.bugReportStatusList = response[0].list.slice()
      this.dsStatus = response[0].list.slice()
      this.bugReportStatusList.unshift({ minorCd: '', minorNm: '전체' })
      //고객지원 유저[1]
      this.dsSupportList = response[1].list.slice()
    })
  },
  methods: {
    btnAdd() {
      this.addYn = true
      //추가일때도 popup의 watch때문에 null 보냄
      this.selectedCellInfo = null
      this.popupTitle = 'addCustomerSupport'
      this.popupVisible = true
    },
    showPopup(cellInfo) {
      this.addYn = false
      this.selectedCellInfo = cellInfo
      this.popupTitle = 'customerSupportDetail'
      this.popupVisible = true
    },
    setSearchDate(e, div) {
      if (div === 'start') {
        this.searchStartDate = e.replace(/[^0-9]/g, '')
      } else if (div === 'end') {
        this.searchEndDate = e.replace(/[^0-9]/g, '')
      }
    },
    convertDateFormatYYYYMMDD(fullDatetime) {
      if (fullDatetime && fullDatetime.length > 10) {
        fullDatetime = fullDatetime
          .substring(0, 10)
          .replace('-', '.')
          .replace('-', '.')
      }

      return fullDatetime
    },
    btnSearch(msgYn) {
      return new Promise((resolve, reject) => {
        var param = {
          startDt: this.searchStartDate.replace(/[^0-9]/g, ''),
          endDt: this.searchEndDate.replace(/[^0-9]/g, ''),
          compId: this.getCompId()
        }
        this.openLoading()

        getBugReport(param, msgYn)
          .then(res => {
            if (res.success) {
              this.gridMain = res.list
              this.gridInit(this.DataGrids[0])
              this.FocusFirstRow(this.DataGrids[0])
              resolve(true)
            }
          })
          .catch(e => reject(e))
          .finally(() => {
            this.endLoading()
          })
      })
    },
    popupClose() {
      this.popupVisible = false
      this.btnSearch(false)
    }
  }
}
</script>

<style lang="scss"></style>
